CREATE TYPE "TradeSessionRunStatus" AS ENUM ('QUEUING','RUNNING','SETTLING','COMPLETED','PARTIAL_FAILURE','FAILED');
CREATE TYPE "AiTradeJobStatus" AS ENUM ('QUEUED','RUNNING','COMPLETED','FAILED','DEAD');
CREATE TYPE "AiFinancialTradeStatus" AS ENUM ('LOCKED','SETTLING','SETTLED','FAILED');
CREATE TYPE "AiOutboxStatus" AS ENUM ('PENDING','PROCESSING','SENT','DEAD');
CREATE TABLE "TradeSessionRun" ("id" TEXT PRIMARY KEY,"sessionId" TEXT NOT NULL,"localTradingDate" VARCHAR(10) NOT NULL,"tradeType" TEXT NOT NULL DEFAULT 'AI_BOT',"timeZone" TEXT NOT NULL,"scheduledStartAt" TIMESTAMP(3) NOT NULL,"referencePriceAt" TIMESTAMP(3) NOT NULL,"scheduledSettleAt" TIMESTAMP(3) NOT NULL,"officialSettledAt" TIMESTAMP(3) NOT NULL,"pair" TEXT NOT NULL,"direction" TEXT NOT NULL,"profitRate" DECIMAL(12,8) NOT NULL,"resultSource" TEXT NOT NULL,"status" "TradeSessionRunStatus" NOT NULL DEFAULT 'QUEUING',"totalEligible" INTEGER NOT NULL DEFAULT 0,"totalQueued" INTEGER NOT NULL DEFAULT 0,"totalStarted" INTEGER NOT NULL DEFAULT 0,"totalFailed" INTEGER NOT NULL DEFAULT 0,"totalSettled" INTEGER NOT NULL DEFAULT 0,"queueCompletedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AiFinancialWallet" ("userId" TEXT PRIMARY KEY,"availableFuture" DECIMAL(24,8) NOT NULL,"lockedFuture" DECIMAL(24,8) NOT NULL DEFAULT 0,"completedProfit" DECIMAL(24,8) NOT NULL DEFAULT 0,"version" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AiFinancialTrade" ("id" TEXT PRIMARY KEY,"executionKey" TEXT NOT NULL,"sessionRunId" TEXT NOT NULL,"userId" TEXT NOT NULL,"subscriptionId" TEXT NOT NULL,"tradeType" TEXT NOT NULL,"balanceSnapshot" DECIMAL(24,8) NOT NULL,"tradePercentage" DECIMAL(12,8) NOT NULL,"principal" DECIMAL(24,8) NOT NULL,"profitRate" DECIMAL(12,8) NOT NULL,"profit" DECIMAL(24,8) NOT NULL,"status" "AiFinancialTradeStatus" NOT NULL DEFAULT 'LOCKED',"officialStartedAt" TIMESTAMP(3) NOT NULL,"officialSettledAt" TIMESTAMP(3),"processingStartedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"processingSettledAt" TIMESTAMP(3),"failureCode" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "AiFinancialTrade_principal_positive" CHECK ("principal">0),CONSTRAINT "AiFinancialTrade_profit_nonnegative" CHECK ("profit">=0));
CREATE TABLE "AiWalletLedger" ("id" TEXT PRIMARY KEY,"idempotencyKey" TEXT NOT NULL,"userId" TEXT NOT NULL,"tradeId" TEXT NOT NULL,"operation" TEXT NOT NULL,"amount" DECIMAL(24,8) NOT NULL,"availableBefore" DECIMAL(24,8) NOT NULL,"availableAfter" DECIMAL(24,8) NOT NULL,"lockedBefore" DECIMAL(24,8) NOT NULL,"lockedAfter" DECIMAL(24,8) NOT NULL,"officialAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "AiTradeJob" ("id" TEXT PRIMARY KEY,"jobKey" TEXT NOT NULL,"queueName" TEXT NOT NULL,"bullJobId" TEXT,"sessionRunId" TEXT NOT NULL,"userId" TEXT,"tradeId" TEXT,"kind" TEXT NOT NULL,"status" "AiTradeJobStatus" NOT NULL DEFAULT 'QUEUED',"attempts" INTEGER NOT NULL DEFAULT 0,"failureCode" TEXT,"failureMessage" TEXT,"startedAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "AiOutboxEvent" ("id" TEXT PRIMARY KEY,"idempotencyKey" TEXT NOT NULL,"aggregateType" TEXT NOT NULL,"aggregateId" TEXT NOT NULL,"userId" TEXT NOT NULL,"eventType" TEXT NOT NULL,"payload" JSONB NOT NULL,"status" "AiOutboxStatus" NOT NULL DEFAULT 'PENDING',"attempts" INTEGER NOT NULL DEFAULT 0,"availableAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"lockedAt" TIMESTAMP(3),"sentAt" TIMESTAMP(3),"lastError" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE UNIQUE INDEX "TradeSessionRun_session_key" ON "TradeSessionRun"("localTradingDate","sessionId","tradeType"); CREATE INDEX "TradeSessionRun_session_status_idx" ON "TradeSessionRun"("sessionId","status"); CREATE INDEX "TradeSessionRun_settle_idx" ON "TradeSessionRun"("status","scheduledSettleAt");
CREATE UNIQUE INDEX "AiFinancialTrade_executionKey_key" ON "AiFinancialTrade"("executionKey"); CREATE UNIQUE INDEX "AiFinancialTrade_user_session_type_key" ON "AiFinancialTrade"("userId","sessionRunId","tradeType"); CREATE INDEX "AiFinancialTrade_session_status_idx" ON "AiFinancialTrade"("sessionRunId","status"); CREATE INDEX "AiFinancialTrade_user_session_idx" ON "AiFinancialTrade"("userId","sessionRunId");
CREATE UNIQUE INDEX "AiWalletLedger_idempotencyKey_key" ON "AiWalletLedger"("idempotencyKey"); CREATE INDEX "AiWalletLedger_trade_operation_idx" ON "AiWalletLedger"("tradeId","operation"); CREATE INDEX "AiWalletLedger_user_created_idx" ON "AiWalletLedger"("userId","createdAt");
CREATE UNIQUE INDEX "AiTradeJob_jobKey_key" ON "AiTradeJob"("jobKey"); CREATE UNIQUE INDEX "AiTradeJob_bullJobId_key" ON "AiTradeJob"("bullJobId"); CREATE INDEX "AiTradeJob_session_status_idx" ON "AiTradeJob"("sessionRunId","status"); CREATE INDEX "AiTradeJob_queue_pending_idx" ON "AiTradeJob"("queueName","status","createdAt");
CREATE UNIQUE INDEX "AiOutboxEvent_idempotencyKey_key" ON "AiOutboxEvent"("idempotencyKey"); CREATE INDEX "AiOutboxEvent_pending_idx" ON "AiOutboxEvent"("status","availableAt","id"); CREATE INDEX "AiOutboxEvent_aggregate_idx" ON "AiOutboxEvent"("aggregateId","eventType");
ALTER TABLE "AiFinancialWallet" ADD CONSTRAINT "AiFinancialWallet_user_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE RESTRICT;
ALTER TABLE "AiFinancialTrade" ADD CONSTRAINT "AiFinancialTrade_run_fkey" FOREIGN KEY ("sessionRunId") REFERENCES "TradeSessionRun"("id") ON DELETE RESTRICT; ALTER TABLE "AiFinancialTrade" ADD CONSTRAINT "AiFinancialTrade_wallet_fkey" FOREIGN KEY ("userId") REFERENCES "AiFinancialWallet"("userId") ON DELETE RESTRICT;
ALTER TABLE "AiWalletLedger" ADD CONSTRAINT "AiWalletLedger_wallet_fkey" FOREIGN KEY ("userId") REFERENCES "AiFinancialWallet"("userId") ON DELETE RESTRICT; ALTER TABLE "AiWalletLedger" ADD CONSTRAINT "AiWalletLedger_trade_fkey" FOREIGN KEY ("tradeId") REFERENCES "AiFinancialTrade"("id") ON DELETE RESTRICT;
ALTER TABLE "AiTradeJob" ADD CONSTRAINT "AiTradeJob_run_fkey" FOREIGN KEY ("sessionRunId") REFERENCES "TradeSessionRun"("id") ON DELETE RESTRICT;
CREATE INDEX "AiBotSubscription_eligible_idx" ON "AiBotSubscription"("status","expiresAt","userId","id");
INSERT INTO "AiFinancialWallet" ("userId","availableFuture","lockedFuture","completedProfit","version","createdAt","updatedAt") SELECT s."userId",COALESCE((s."wallet"->'wallets'->'future'->>'balance')::numeric,0),COALESCE((s."wallet"->>'lockedFutureTradeCapital')::numeric,0),COALESCE((s."wallet"->>'totalCompletedTradingProfit')::numeric,0),0,CURRENT_TIMESTAMP,CURRENT_TIMESTAMP FROM "UserState" s ON CONFLICT ("userId") DO NOTHING;
